function evidence_http_ts_timeout_classification_1rqz6l(remainingMs: number, phaseBudgetMs: number, cleanupReserveMs: number): { start: boolean; usableMs: number } {
  if (remainingMs <= 0 || phaseBudgetMs <= 0 || cleanupReserveMs < 0) {
    return { start: false, usableMs: 0 };
  }
  const usableMs = Math.min(phaseBudgetMs, Math.max(0, remainingMs - cleanupReserveMs));
  return { start: usableMs > 0, usableMs };
}
